26	func (f *CommandFactory) newServerWorkersListCommand() *cobra.Command {
27		var asJSON bool
28	
29		cmd := &cobra.Command{
30			Use:   "list",
31			Short: "List agent execution workers",
32			RunE: func(cmd *cobra.Command, args []string) error {
33				base := resolveServerURL(f.WorkingDir)
34	
35				resp, err := newLocalServerClient().Get(base + "/api/agent/workers")
36				if err != nil {
37					return fmt.Errorf("server request: %w", err)
38				}
39				defer func() { _ = resp.Body.Close() }()
40	
41				body, err := io.ReadAll(resp.Body)
42				if err != nil {
43					return fmt.Errorf("reading response: %w", err)
44				}
45	
46				if asJSON {
47					fmt.Fprintln(cmd.OutOrStdout(), string(body))
48					return nil
49				}
50	
51				var workers []workerRecord
52				if err := json.Unmarshal(body, &workers); err != nil {
53					return fmt.Errorf("parsing response: %w", err)
54				}
55	
56				if len(workers) == 0 {
57					fmt.Fprintln(cmd.OutOrStdout(), "No workers.")
58					return nil
59				}
60	
61				for _, w := range workers {
62					state := w.State
63					if state == "exited" {
64						if w.LastResult.Status != "" {
65							state = w.LastResult.Status
66						}
67					}
68					model := w.Model
69					if model == "" && w.LastResult.Model != "" {
70						model = w.LastResult.Model
71					}
72					bead := w.LastResult.BeadID
73					if bead == "" {
74						bead = "-"
75					}
76					age := formatDuration(time.Since(w.StartedAt))
77					fmt.Fprintf(cmd.OutOrStdout(), "%-36s %-6s %-18s %-24s %s\n",
78						w.ID, age, state, model, bead)
79				}
80				return nil
81			},
82		}
83	
84		cmd.Flags().BoolVar(&asJSON, "json", false, "Output as JSON")
85	
86		return cmd
87	}
