240	func formatDuration(d time.Duration) string {
241		if d < time.Minute {
242			return fmt.Sprintf("%.0fs", d.Seconds())
243		}
244		if d < time.Hour {
245			return fmt.Sprintf("%.0fm", d.Minutes())
246		}
247		hours := int(d.Hours())
248		mins := int(d.Minutes()) % 60
249		if mins == 0 {
250			return fmt.Sprintf("%dh", hours)
251		}
252		return fmt.Sprintf("%dh%dm", hours, mins)
253	}
