30	type preClaimGitOps interface {
31		CurrentBranch(dir string) (string, error)
32		FetchOriginAncestryCheck(dir, targetBranch string) (agent.PreClaimResult, error)
33	}
34	
35	// buildCLIPreClaimHook returns a PreClaimHook for inline queue work
36	// that fetches origin and verifies ancestry before each bead claim.
37	func buildCLIPreClaimHook(projectRoot string, gitOps preClaimGitOps) func(ctx context.Context) error {
38		return func(ctx context.Context) error {
39			branch, err := gitOps.CurrentBranch(projectRoot)
40			if err != nil {
41				return nil // can't determine branch — skip
42			}
43			res, err := gitOps.FetchOriginAncestryCheck(projectRoot, branch)
44			if err != nil {
45				if !agent.IsIgnorableFetchOriginError(err) {
46					return err
47				}
48				return nil
49			}
50			if res.Action == "diverged" {
51				return fmt.Errorf("local branch %s has diverged from origin (local=%s origin=%s); reconcile manually before claiming",
52					branch, res.LocalSHA, res.OriginSHA)
53			}
54			return nil
55		}
56	}
