58	func buildCLIResourceChecker(projectRoot string, override agent.ExecutionResourceChecker) agent.ExecutionResourceChecker {
59		if override != nil {
60			return override
61		}
62		return agent.NewExecutionResourceChecker(projectRoot, &agent.RealGitOps{})
63	}
