65	// resolveServerURL determines the base URL for the running DDx server.
66	func resolveServerURL(projectRoot string) string {
67		if u := os.Getenv("DDX_SERVER_URL"); u != "" {
68			return u
69		}
70		if u := serverpkg.ReadServerAddr(); u != "" {
71			return rewriteBindAddrForClient(u)
72		}
73		return "https://127.0.0.1:7743"
74	}
75	
76	func rewriteBindAddrForClient(u string) string {
77		for _, bind := range []string{"//0.0.0.0:", "//[::]:", "//[::0]:"} {
78			if idx := strings.Index(u, bind); idx >= 0 {
79				return u[:idx] + "//127.0.0.1:" + u[idx+len(bind):]
80			}
81		}
82		return u
83	}
84	
85	// newLocalServerClient returns an http.Client configured for the local DDx server.
86	func newLocalServerClient() *http.Client {
87		return &http.Client{
88			Timeout: 30 * time.Second,
89			Transport: &http.Transport{
90				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec // local self-signed cert
91			},
92		}
93	}
94	
95	// resolveWorktree creates or reuses a named worktree under .worktrees/.
96	func resolveWorktree(repoRoot, name string) (string, error) {
97		if repoRoot == "" {
98			out, err := gitpkg.Command(context.Background(), "", "rev-parse", "--show-toplevel").Output()
99			if err != nil {
100				return "", fmt.Errorf("cannot detect repo root: %w", err)
101			}
102			repoRoot = strings.TrimSpace(string(out))
103		}
104	
105		wtDir := filepath.Join(repoRoot, ".worktrees", name)
106		if _, err := os.Stat(wtDir); err == nil {
107			return wtDir, nil
108		}
109	
110		cmd := gitpkg.Command(context.Background(), repoRoot, "worktree", "add", wtDir, "-b", name)
111		if out, err := cmd.CombinedOutput(); err != nil {
112			cmd2 := gitpkg.Command(context.Background(), repoRoot, "worktree", "add", wtDir, name)
113			if out2, err2 := cmd2.CombinedOutput(); err2 != nil {
114				return "", fmt.Errorf("git worktree add failed: %s\n%s", string(out), string(out2))
115			}
116		}
117	
118		return wtDir, nil
119	}
