13	func (f *CommandFactory) newSkillsCommand() *cobra.Command {
14		cmd := &cobra.Command{
15			Use:   "skills",
16			Short: "Validate bundled skill packages",
17			Long: `Validate SKILL.md metadata for DDx or plugin skill packages.
18	
19	The validator enforces the DDx skill contract:
20	• YAML frontmatter must exist
21	• top-level "name" is required
22	• top-level "description" is required
23	• nested "skill:" metadata is rejected
24	• markdown body must not be empty
25	
26	Examples:
27	  ddx skills check
28	  ddx skills check skills
29	  ddx skills check .agents/skills
30	  ddx skills check .ddx/plugins/ddx
31	  ddx skills check .ddx/plugins/helix/skills`,
32			Run: func(cmd *cobra.Command, args []string) {
33				_ = cmd.Help()
34			},
35		}
36	
37		cmd.AddCommand(f.newSkillsCheckCommand())
38		return cmd
39	}
