41	func (f *CommandFactory) newSkillsCheckCommand() *cobra.Command {
42		return &cobra.Command{
43			Use:   "check [path...]",
44			Short: "Validate SKILL.md metadata",
45			Args:  cobra.ArbitraryArgs,
46			RunE: func(cmd *cobra.Command, args []string) error {
47				return f.runSkillsCheck(cmd, args)
48			},
49		}
50	}
51	
52	func (f *CommandFactory) runSkillsCheck(cmd *cobra.Command, args []string) error {
53		paths := args
54		if len(paths) == 0 {
55			paths = f.defaultSkillCheckPaths()
56		}
57	
58		files, issues := skills.ValidatePaths(paths)
59		for _, issue := range issues {
60			_, _ = fmt.Fprintf(cmd.ErrOrStderr(), "skill issue: %s\n", issue.Error())
61		}
62		if len(issues) > 0 {
63			return NewExitError(ExitCodeGeneralError, fmt.Sprintf("skill validation failed with %d issue(s)", len(issues)))
64		}
65	
66		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "validated %d skill files\n", len(files))
67		return nil
68	}
69	
70	func (f *CommandFactory) defaultSkillCheckPaths() []string {
71		projectRoot := gitpkg.FindProjectRoot(f.WorkingDir)
72		if projectRoot == "" {
73			projectRoot = f.WorkingDir
74		}
75	
76		candidates := []string{
77			filepath.Join(projectRoot, "skills"),
78			filepath.Join(projectRoot, ".agents", "skills"),
79			filepath.Join(projectRoot, ".claude", "skills"),
80			filepath.Join(projectRoot, ".ddx", "plugins", "ddx"),
81			filepath.Join(projectRoot, "cli", "internal", "skills"),
82		}
83	
84		var paths []string
85		for _, candidate := range candidates {
86			if _, err := os.Stat(candidate); err == nil {
87				paths = append(paths, candidate)
88			}
89		}
90		return paths
91	}
