272	func (s *Service) Summary(query Query) (AggregateSummary, error) {
273		beads, sessions, _, sessionCostPresent, err := s.loadInputs()
274		if err != nil {
275			return AggregateSummary{}, err
276		}
277	
278		costReport, err := s.Cost(query)
279		if err != nil {
280			return AggregateSummary{}, err
281		}
282		cycleReport, err := s.CycleTime(query)
283		if err != nil {
284			return AggregateSummary{}, err
285		}
286		reworkReport, err := s.Rework(query)
287		if err != nil {
288			return AggregateSummary{}, err
289		}
290	
291		var summary AggregateSummary
292		visibleBeads, visibleBeadIDs := beadsVisibleInSummaryWindow(beads, query, costReport, cycleReport, reworkReport)
293		summary.Beads.Total = len(visibleBeads)
294	
295		for _, b := range visibleBeads {
296			switch b.Status {
297			case bead.StatusOpen:
298				summary.Beads.Open++
299			case bead.StatusInProgress:
300				summary.Beads.InProgress++
301			case bead.StatusClosed:
302				summary.Beads.Closed++
303			case bead.StatusBlocked:
304				summary.Beads.Blocked++
305			case bead.StatusProposed:
306				summary.Beads.Proposed++
307			case bead.StatusCancelled:
308				summary.Beads.Cancelled++
309			}
310		}
311		var cycleKnownTotalMS int64
312		for _, row := range cycleReport.Beads {
313			if query.HasSince {
314				if _, ok := visibleBeadIDs[row.BeadID]; !ok {
315					continue
316				}
317			}
318			if row.CycleState == stateKnown {
319				summary.Beads.KnownCycleTime++
320				summary.CycleTime.KnownCount++
321				if row.CycleTimeMS != nil {
322					cycleKnownTotalMS += *row.CycleTimeMS
323					if summary.CycleTime.MinMS == nil || *row.CycleTimeMS < *summary.CycleTime.MinMS {
324						summary.CycleTime.MinMS = int64Ptr(*row.CycleTimeMS)
325					}
326					if summary.CycleTime.MaxMS == nil || *row.CycleTimeMS > *summary.CycleTime.MaxMS {
327						summary.CycleTime.MaxMS = int64Ptr(*row.CycleTimeMS)
328					}
329				}
330			} else {
331				summary.Beads.UnknownCycleTime++
332				summary.CycleTime.UnknownCount++
333			}
334		}
335		if summary.CycleTime.KnownCount > 0 {
336			avg := cycleKnownTotalMS / int64(summary.CycleTime.KnownCount)
337			summary.CycleTime.AverageMS = &avg
338		}
339	
340		costBeadCount := 0
341		featureIDs := make(map[string]struct{})
342		for _, row := range costReport.Beads {
343			if query.HasSince {
344				if _, ok := visibleBeadIDs[row.BeadID]; !ok && len(row.SessionIDs) == 0 {
345					continue
346				}
347			}
348			costBeadCount++
349			if row.SpecID != "" {
350				featureIDs[row.SpecID] = struct{}{}
351			}
352			switch row.CostState {
353			case stateKnown:
354				summary.Beads.KnownCost++
355			case stateEstimated:
356				summary.Beads.EstimatedCost++
357			default:
358				summary.Beads.UnknownCost++
359			}
360		}
361	
362		summary.Cost.Beads = costBeadCount
363		summary.Cost.Features = len(featureIDs)
364		for _, row := range costReport.Beads {
365			if query.HasSince {
366				if _, ok := visibleBeadIDs[row.BeadID]; !ok && len(row.SessionIDs) == 0 {
367					continue
368				}
369			}
370			switch row.CostState {
371			case stateKnown:
372				if row.CostUSD != nil {
373					summary.Cost.KnownCostUSD += *row.CostUSD
374				}
375			case stateEstimated:
376				if row.CostUSD != nil {
377					summary.Cost.EstimatedCostUSD += *row.CostUSD
378				}
379			default:
380				summary.Cost.UnknownBeads++
381			}
382		}
383	
384		for _, sess := range sessions {
385			if query.HasSince && sess.Timestamp.Before(query.Since) {
386				continue
387			}
388			summary.Sessions.Total++
389			summary.Sessions.InputTokens += sessionInputTokens(sess)
390			summary.Sessions.OutputTokens += sessionOutputTokens(sess)
391			summary.Sessions.TotalTokens += sessionTotalTokens(sess)
392			if sessionBeadID(sess) != "" {
393				summary.Sessions.Correlated++
394			} else {
395				summary.Sessions.Uncorrelated++
396			}
397			switch sessionCostState(sess, sessionCostPresent[sess.ID]) {
398			case stateKnown:
399				summary.Sessions.KnownCost++
400			case stateEstimated:
401				summary.Sessions.EstimatedCost++
402			default:
403				summary.Sessions.UnknownCost++
404			}
405			if cost := sessionDerivedCost(sess, sessionCostPresent[sess.ID]); cost != nil {
406				summary.Sessions.CostUSD += *cost
407			}
408		}
409	
410		for _, row := range reworkReport.Beads {
411			if query.HasSince {
412				if _, ok := visibleBeadIDs[row.BeadID]; !ok {
413					continue
414				}
415			}
416			if row.ReworkState != stateKnown {
417				summary.Rework.UnknownCount++
418				continue
419			}
420			summary.Rework.KnownClosed++
421			if row.Reopened {
422				summary.Rework.KnownReopened++
423				summary.Beads.Reopened++
424			}
425			if row.RevisionCount != nil {
426				summary.Rework.RevisionCount += *row.RevisionCount
427			}
428		}
429		if summary.Rework.KnownClosed > 0 {
430			summary.Rework.ReopenRate = float64(summary.Rework.KnownReopened) / float64(summary.Rework.KnownClosed)
431		}
432		return summary, nil
433	}
