627	func beadsVisibleInSummaryWindow(beads []bead.Bead, query Query, costReport CostReport, cycleReport CycleTimeReport, reworkReport ReworkReport) ([]bead.Bead, map[string]struct{}) {
628		if !query.HasSince || query.Since.IsZero() {
629			visibleIDs := make(map[string]struct{}, len(beads))
630			for _, b := range beads {
631				visibleIDs[b.ID] = struct{}{}
632			}
633			return beads, visibleIDs
634		}
635	
636		visibleIDs := make(map[string]struct{}, len(beads))
637		for _, row := range costReport.Beads {
638			if len(row.SessionIDs) > 0 {
639				visibleIDs[row.BeadID] = struct{}{}
640			}
641		}
642		for _, row := range cycleReport.Beads {
643			if row.FirstClosedAt != nil {
644				visibleIDs[row.BeadID] = struct{}{}
645			}
646		}
647		for _, row := range reworkReport.Beads {
648			if row.FirstClosedAt != nil {
649				visibleIDs[row.BeadID] = struct{}{}
650			}
651		}
652	
653		visible := make([]bead.Bead, 0, len(beads))
654		for _, b := range beads {
655			if _, ok := visibleIDs[b.ID]; !ok {
656				continue
657			}
658			visible = append(visible, b)
659		}
660		return visible, visibleIDs
661	}
