855	func buildFeatureCostRows(beadRows []BeadCostRow) []FeatureCostRow {
856		grouped := make(map[string]*FeatureCostRow)
857		for _, row := range beadRows {
858			if row.SpecID == "" {
859				continue
860			}
861			entry, ok := grouped[row.SpecID]
862			if !ok {
863				entry = &FeatureCostRow{SpecID: row.SpecID}
864				grouped[row.SpecID] = entry
865			}
866			entry.BeadIDs = append(entry.BeadIDs, row.BeadID)
867			entry.InputTokens += row.InputTokens
868			entry.OutputTokens += row.OutputTokens
869			entry.TotalTokens += row.TotalTokens
870			if row.CostState == stateUnknown || row.CostUSD == nil {
871				entry.UnknownBeads++
872				continue
873			}
874			switch row.CostState {
875			case stateKnown:
876				if entry.CostUSD == nil {
877					entry.CostUSD = float64Ptr(0)
878				}
879			case stateEstimated:
880				if entry.CostState == stateKnown {
881					entry.CostState = stateEstimated
882				}
883			}
884			if entry.CostUSD == nil {
885				entry.CostUSD = float64Ptr(0)
886			}
887			*entry.CostUSD += *row.CostUSD
888			if row.CostState == stateEstimated {
889				entry.CostState = stateEstimated
890			} else if entry.CostState == "" {
891				entry.CostState = stateKnown
892			}
893		}
894	
895		out := make([]FeatureCostRow, 0, len(grouped))
896		for _, row := range grouped {
897			sort.Strings(row.BeadIDs)
898			if row.CostUSD != nil {
899				if row.CostState == "" {
900					row.CostState = stateKnown
901				}
902			} else {
903				row.CostState = stateUnknown
904			}
905			out = append(out, *row)
906		}
907		sort.Slice(out, func(i, j int) bool {
908			return out[i].SpecID < out[j].SpecID
909		})
910		return out
911	}
