1056	func buildReworkRow(workingDir string, b bead.Bead, sessionByID map[string]agent.SessionEntry) ReworkRow {
1057		row := ReworkRow{
1058			BeadID: b.ID,
1059			Title:  b.Title,
1060			SpecID: extraString(b, "spec-id", "spec_id"),
1061			Status: b.Status,
1062		}
1063	
1064		events := beadEvents(b)
1065		transitions := recognizedTransitions(events)
1066		sort.Slice(transitions, func(i, j int) bool {
1067			return transitions[i].At.Before(transitions[j].At)
1068		})
1069	
1070		closeAt, provenance := firstCloseEvidence(workingDir, b, transitions, sessionByID)
1071		if closeAt == nil {
1072			return row
1073		}
1074		row.FirstClosedAt = closeAt
1075		row.Provenance = append(row.Provenance, provenance...)
1076		if len(transitions) == 0 {
1077			return row
1078		}
1079		row.ReworkState = stateKnown
1080	
1081		var reopenCount int
1082		var revisionCount int
1083		var sawClose bool
1084		for _, tr := range transitions {
1085			if tr.At.Before(*closeAt) {
1086				continue
1087			}
1088			if tr.Status == bead.StatusClosed {
1089				sawClose = true
1090				continue
1091			}
1092			if sawClose && (tr.Status == bead.StatusOpen || tr.Status == bead.StatusInProgress) {
1093				reopenCount++
1094			}
1095			if tr.Status != bead.StatusClosed {
1096				revisionCount++
1097			}
1098		}
1099		row.Reopened = reopenCount > 0
1100		row.ReopenCount = intPtr(reopenCount)
1101		row.RevisionCount = intPtr(revisionCount)
1102		return row
1103	}
