1154	func firstCloseEvidence(workingDir string, b bead.Bead, transitions []statusTransition, sessionByID map[string]agent.SessionEntry) (*time.Time, []SourceRef) {
1155		var eventCloseTimes []time.Time
1156		var eventProvenance []SourceRef
1157		for _, tr := range transitions {
1158			if tr.Status != bead.StatusClosed {
1159				continue
1160			}
1161			ts := tr.At
1162			eventCloseTimes = append(eventCloseTimes, ts)
1163			eventProvenance = append(eventProvenance, SourceRef{
1164				BeadID:    b.ID,
1165				Timestamp: &ts,
1166				Source:    "event",
1167			})
1168		}
1169		if len(eventCloseTimes) > 0 {
1170			sort.Slice(eventCloseTimes, func(i, j int) bool { return eventCloseTimes[i].Before(eventCloseTimes[j]) })
1171			first := eventCloseTimes[0]
1172			return &first, eventProvenance
1173		}
1174	
1175		if sha := extraString(b, "closing_commit_sha"); sha != "" {
1176			if ts, ok := commitTimeWithWorkingDir(workingDir, sha); ok {
1177				return &ts, []SourceRef{{
1178					BeadID:           b.ID,
1179					ClosingCommitSHA: sha,
1180					Timestamp:        &ts,
1181					Source:           "commit",
1182				}}
1183			}
1184		}
1185	
1186		if sessionID := extraString(b, "session_id", "session-id"); sessionID != "" {
1187			if sess, ok := sessionByID[sessionID]; ok {
1188				ts := sess.Timestamp.UTC()
1189				return &ts, []SourceRef{{
1190					BeadID:          b.ID,
1191					SessionID:       sess.ID,
1192					NativeSessionID: sess.NativeSessionID,
1193					NativeLogRef:    sess.NativeLogRef,
1194					Timestamp:       &ts,
1195					Source:          "session",
1196				}}
1197			}
1198		}
1199	
1200		return nil, nil
1201	}
