1222			if event.CreatedAt.IsZero() {
1223				continue
1224			}
1225			ts := event.CreatedAt.UTC()
1226			out = append(out, SourceRef{
1227				BeadID:    beadID,
1228				Timestamp: &ts,
1229				Source:    event.Source,
1230			})
1231		}
1232		return out
1233	}
