26			filepath.Join(projectRoot, ".claude", "skills", "ddx", "bead-lifecycle", "SKILL.md"),
27		}
28		missing := true
29		for _, p := range checked {
30			if _, err := os.Stat(p); err == nil {
31				missing = false
32				break
33			}
34		}
35		return projectRuntimePreflightResult{
36			ProjectRoot:          projectRoot,
37			MissingBeadLifecycle: missing,
38			CheckedPaths:         checked,
39			LegacySymlinkDirs:    legacySkillSymlinkDirs(projectRoot),
40		}
41	}
