43	// emitPreflightWarning writes a warn-level preflight message to w when the
44	// project-local skill layout is degraded. Used by work/try before dispatch.
45	// Callers are responsible for emitting at most once per process via sync.Once.
46	func emitPreflightWarning(w io.Writer, result projectRuntimePreflightResult) {
47		if !result.MissingBeadLifecycle && len(result.LegacySymlinkDirs) == 0 {
48			return
49		}
50		fmt.Fprintf(w, "preflight warning: project-local skill layout is degraded (project root: %s)\n", result.ProjectRoot)
51		if result.MissingBeadLifecycle {
52			for _, p := range result.CheckedPaths {
53				fmt.Fprintf(w, "  checked: %s\n", p)
54			}
55		}
56		for _, dir := range result.LegacySymlinkDirs {
57			fmt.Fprintf(w, "  legacy skill symlinks under %s\n", dir)
58		}
59		fmt.Fprintf(w, "  run: ddx update --force\n")
60		fmt.Fprintf(w, "  run: ddx doctor\n")
61	}
62	
63	// emitServerPreflightDiagnostics writes degraded startup diagnostics to w.
64	// Called by the server RunE before ListenAndServeTLS to surface skill layout
65	// issues without blocking server startup (missing bead-lifecycle is not fatal
66	// for the server).
67	func emitServerPreflightDiagnostics(w io.Writer, result projectRuntimePreflightResult) {
68		if !result.MissingBeadLifecycle && len(result.LegacySymlinkDirs) == 0 {
69			return
70		}
71		fmt.Fprintf(w, "DDx server: degraded skill layout (project root: %s)\n", result.ProjectRoot)
72		if result.MissingBeadLifecycle {
73			fmt.Fprintf(w, "  bead-lifecycle skill not found; lifecycle hooks will not fire\n")
74			for _, p := range result.CheckedPaths {
75				fmt.Fprintf(w, "  checked: %s\n", p)
76			}
77		}
78		for _, dir := range result.LegacySymlinkDirs {
79			fmt.Fprintf(w, "  legacy skill symlinks under %s\n", dir)
80		}
81		fmt.Fprintf(w, "  run: ddx update --force\n")
82		fmt.Fprintf(w, "  run: ddx doctor\n")
83	}
